/**
 * HTTP server for Smithery scanning.
 * Serves the auto-generated server-card.json at /.well-known/mcp/server-card.json
 * and the MCP Streamable HTTP endpoint at /mcp.
 *
 * The server card is generated by `npm run release` (scripts/publish.js).
 * Run standalone: node scripts/http-scan-server.js
 */
import http from 'node:http';
import { readFileSync } from 'node:fs';
import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
import { StreamableHTTPServerTransport } from '@modelcontextprotocol/sdk/server/streamableHttp.js';
import { SessionManager } from '../src/session-manager.js';
import { registerTools } from '../src/tools.js';

const PORT = 3456;
const HTTP_BAD_REQUEST = 400;
const HTTP_METHOD_NOT_ALLOWED = 405;
const HTTP_INTERNAL_SERVER_ERROR = 500;
const JSONRPC_PARSE_ERROR = -32700;
const JSONRPC_INTERNAL_ERROR = -32603;

// Server card is auto-generated by publish.js — do not edit manually
const SERVER_CARD = JSON.parse(readFileSync(new URL('../server-card.json', import.meta.url), 'utf8'));

function writeJson(res, statusCode, body) {
  if (res.headersSent || res.writableEnded) return;
  res.writeHead(statusCode, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify(body));
}

function createJsonRpcError(code, message) {
  return { jsonrpc: '2.0', error: { code, message }, id: null };
}

async function closeMcpResources(server, transport) {
  const tasks = [];
  if (transport) tasks.push(Promise.resolve(transport.close()));
  if (server) tasks.push(Promise.resolve(server.close()));
  await Promise.allSettled(tasks);
}

function createServer() {
  const server = new McpServer({ name: 'smart-terminal-mcp', version: SERVER_CARD.serverInfo.version });
  const manager = new SessionManager();
  registerTools(server, manager);
  return server;
}

const httpServer = http.createServer(async (req, res) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, GET, DELETE, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Accept, Mcp-Session-Id');
  res.setHeader('Access-Control-Expose-Headers', 'Mcp-Session-Id');

  if (req.method === 'OPTIONS') { res.writeHead(204); res.end(); return; }

  // Static server card for Smithery scanning
  if (req.url === '/.well-known/mcp/server-card.json') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify(SERVER_CARD));
    console.log('✓ Served server-card.json');
    return;
  }

  // MCP Streamable HTTP endpoint
  if (req.url === '/mcp' && req.method === 'POST') {
    let server;
    let transport;
    let isParseError = false;
    let isClosed = false;

    const closeResources = async () => {
      if (isClosed) return;
      isClosed = true;
      await closeMcpResources(server, transport);
    };

    try {
      const chunks = [];
      for await (const chunk of req) chunks.push(chunk);

      let body;
      try {
        body = JSON.parse(Buffer.concat(chunks).toString());
      } catch (error) {
        isParseError = true;
        throw error;
      }

      server = createServer();
      transport = new StreamableHTTPServerTransport({ sessionIdGenerator: undefined });
      res.on('close', () => { void closeResources(); });

      await server.connect(transport);
      await transport.handleRequest(req, res, body);
      console.log('✓ Handled MCP POST request');
    } catch (error) {
      const statusCode = isParseError ? HTTP_BAD_REQUEST : HTTP_INTERNAL_SERVER_ERROR;
      const errorBody = isParseError
        ? createJsonRpcError(JSONRPC_PARSE_ERROR, 'Invalid JSON body.')
        : createJsonRpcError(JSONRPC_INTERNAL_ERROR, 'Internal server error.');

      console.error('✗ Failed to handle MCP POST request:', error);
      await closeResources();
      writeJson(res, statusCode, errorBody);
    }
    return;
  }

  if (req.url === '/mcp' && (req.method === 'GET' || req.method === 'DELETE')) {
    writeJson(res, HTTP_METHOD_NOT_ALLOWED, { jsonrpc: '2.0', error: { code: -32000, message: 'Method not allowed.' }, id: null });
    return;
  }

  res.writeHead(200, { 'Content-Type': 'text/plain' });
  res.end('smart-terminal-mcp HTTP scan server');
});

httpServer.listen(PORT, () => {
  console.log(`\n🌐 MCP HTTP scan server on http://localhost:${PORT}`);
  console.log(`   Server card: http://localhost:${PORT}/.well-known/mcp/server-card.json (${SERVER_CARD.tools.length} tools)`);
  console.log(`   MCP endpoint: http://localhost:${PORT}/mcp\n`);
});
